{
  "title": "History of Burma",
  "description": "This course provides a comprehensive overview of the historical events, cultural developments, and significant figures in the history of Burma, focusing on its journey to independence and beyond.",
  "modules": [
    {
      "id": "module1",
      "title": "Ancient and Colonial Burma",
      "description": "Explore the early civilizations of Burma, including the Pagan Empire, and the impact of British colonial rule on the region."
    },
    {
      "id": "module2",
      "title": "The Road to Independence",
      "description": "Examine the key events and leaders, including Aung San and Aung San Suu Kyi, that shaped the independence movement in Burma."
    },
    {
      "id": "module3",
      "title": "Post-Independence Challenges",
      "description": "Analyze the political, social, and economic challenges faced by Burma after gaining independence in 1948, including military coups and ethnic conflicts."
    },
    {
      "id": "module4",
      "title": "Contemporary Burma",
      "description": "Discuss the recent history of Burma, including the transition to a quasi-democracy, ongoing struggles for human rights, and the role of international relations."
    }
  ]
}
